28	function classify(c) {
29	  const now = Date.now();
30	  const lastTime = c.lastContactTime || c.modifyTime || 0;
31	  const daysAgo = (now - lastTime) / (1000 * 60 * 60 * 24);
32	  const content = (c.latestMessageContent || '').toLowerCase();
33	  const hasContent = content.length > 5;
34	  const isUnread = c.isUnread || c.unreadCount > 0;
35	  const isFromCustomer = c.msgFromCustomer === true;
36	  const contactRead = c.contactRead;
37	
38	  // 关键词
39	  const hasPrice = /price|quote|cost|how much|报价|价格|cuánto|combien|كم|сколько/i.test(content);
40	  const hasSample = /sample|muestra|échantillon|样品|试用|试单/i.test(content);
41	  const hasPayment = /payment|pay|deposit|付款|pago|paiement|دفع|tt\b|wire|transfer/i.test(content);
42	  const hasShipping = /ship|delivery|envío|livraison|快递|海运|dhl|fedex|物流/i.test(content);
43	  const hasComplaint = /complaint|return|refund|damage|defect|wrong|quality issue|not as described|退换|退款|投诉|破损/i.test(content);
44	  const hasNegotiation = /discount|better price|cheaper|moq|minimum|negotiate|better deal|优惠|折扣/i.test(content);
45	  const hasUrgent = /urgent|asap|immediately|尽快|urgente|dringend/i.test(content);
46	
47	  // ===== P0: 紧急 =====
48	  // 1. 有未读 + 客户消息
49	  if (isUnread) {
50	    return { priority: 'P0', tier: 'S', reasons: ['有未读消息'] };
51	  }
52	
53	  // 2. 客户消息 + 售后投诉
54	  if (isFromCustomer && hasComplaint) {
55	    return { priority: 'P0', tier: 'S', reasons: ['售后/投诉'] };
56	  }
57	
58	  // 3. 客户消息 + 24h内 + 询价/付款
59	  if (isFromCustomer && daysAgo <= 1 && (hasPrice || hasPayment)) {
60	    return { priority: 'P0', tier: 'A', reasons: ['24h内询价/付款'] };
61	  }
62	
63	  // 4. 客户未读(contactRead=false) + 近期 + 有内容
64	  if (contactRead === false && daysAgo <= 3 && hasContent) {
65	    return { priority: 'P0', tier: 'A', reasons: ['未读+3天内'] };
66	  }
67	
68	  // 5. 客户消息 + 急迫
69	  if (isFromCustomer && hasUrgent) {
70	    return { priority: 'P0', tier: 'A', reasons: ['紧急措辞'] };
71	  }
72	
73	  // 6. 客户消息 + 谈判中
74	  if (isFromCustomer && hasNegotiation && daysAgo <= 7) {
75	    return { priority: 'P0', tier: 'B', reasons: ['谈判中'] };
76	  }
77	
78	  // ===== P1: 高优 =====
79	  // 7. 客户消息 + 7天内 + 询价/样品/物流
80	  if (isFromCustomer && daysAgo <= 7 && (hasPrice || hasSample || hasShipping || hasPayment)) {
81	    return { priority: 'P1', tier: 'A', reasons: ['近期业务相关'] };
82	  }
83	
84	  // 8. contactRead=false + 14天内
85	  if (contactRead === false && daysAgo <= 14 && hasContent) {
86	    return { priority: 'P1', tier: 'B', reasons: ['待阅读消息'] };
87	  }
88	
89	  // 9. 客户消息 + 14天内
90	  if (isFromCustomer && daysAgo <= 14) {
91	    return { priority: 'P1', tier: 'B', reasons: ['客户近期消息'] };
92	  }
93	
94	  // ===== P2: 待回访 =====
95	  // 10. 30天内互动 + 我方最后发言
96	  if (daysAgo <= 30) {
97	    return { priority: 'P2', tier: 'C', reasons: ['30天内互动'] };
98	  }
99	
100	  // ===== P3: 休眠 =====
101	  return { priority: 'P3', tier: 'C', reasons: [`${Math.round(daysAgo)}天未联系`] };
102	}
