104	async function main() {
105	  console.log('[extract-v2] 连接小满...');
106	  const { talkFrame } = await connect();
107	
108	  // Step 1: 从DOM获取实时状态（未读、方向）
109	  console.log('[1/3] 从DOM获取实时状态...');
110	  const domStatus = await talkFrame.evaluate(() => {
111	    const containers = document.querySelectorAll('.contact-item-container');
112	    const statusMap = {};
113	
114	    containers.forEach(el => {
115	      const text = el.textContent || '';
