125	        .trim();
126	
127	      // 判断消息方向: 我方发出的消息通常有特定前缀
128	      const isFromUs = lastMsg.includes('以上内容') ||
129	        lastMsg.includes('发送了') ||
130	        lastMsg.includes('[文件]') ||
131	        lastMsg.startsWith('Due to your intervention') ||
132	        lastMsg.startsWith('由于您介入');
133	
134	      statusMap[name] = {
135	        isUnread,
136	        msgFromCustomer: !isFromUs && lastMsg.length > 0,
137	        domLastMsg: lastMsg.substring(0, 100),
138	      };
139	    });
140	
141	    return statusMap;
142	  });
143	
144	  console.log(`   DOM中${Object.keys(domStatus).length}个客户`);
145	
146	  // Step 2: 从window变量获取全量数据
147	  console.log('[2/3] 从window提取全量数据...');
148	  const rawCustomers = await talkFrame.evaluate(() => {
149	    const data = window.__conversationListFullData__;
150	    if (!data || !Array.isArray(data)) return [];
151	
152	    return data
153	      .filter(item => {
154	        const name = item.contact?.name || '';
155	        // System accounts (expanded from single Eva check)
156	        if (/Assistant\s*Eva/i.test(name)) return false;
157	        if (/系统通知/.test(name)) return false;
158	        if (/机器人/.test(name)) return false;
159	        if (/^\d{6,}$/.test(name)) return false;
160	        if (!name || name === 'unknown') return false;
161	        return item.available !== false;
162	      })
163	      .map(item => {
164	        const contact = item.contact || {};
165	        const latestMsg = item.latestMessage || {};
166	        return {
167	          name: contact.name || contact.companyName || 'Unknown',
168	          companyName: contact.companyName || '',
169	          countryCode: contact.complianceCountryCode || '',
170	          buyerLevel: contact.userNewLevel || '',
171	          loginId: contact.loginId || '',
172	
173	          unreadCount: item.unreadCount || 0,
174	          muted: item.mute || false,
175	          pinned: item.stayTop || false,
176	          blocked: item.block || false,
177	          replyCountdown: item.replyCountdown || 0,
178	
179	          lastContactTime: item.lastContactTime || item.modifyTime || 0,
180	          joinTime: item.joinTime || 0,
181	          modifyTime: item.modifyTime || 0,
182	
183	          latestMessageContent: latestMsg.content || '',
184	          latestMessageType: latestMsg.messageType || '',
185	          latestMessageTime: latestMsg.gmtChat || 0,
186	          contactRead: latestMsg.contactRead !== undefined ? latestMsg.contactRead : (item.contactRead !== undefined ? item.contactRead : true),
187	
188	          tagInfo: item.tagInfo || null,
189	          cid: item.cid || '',
190	          accountId: contact.accountId || item.accountId || '',
191	        };
192	      });
193	  });
194	
195	  console.log(`   window中${rawCustomers.length}个客户`);
196	
197	  // Step 3: 合并DOM状态到window数据
198	  console.log('[3/3] 合并数据+分类...');
199	  const merged = rawCustomers.map(c => {
200	    const dom = domStatus[c.name];
201	    if (dom) {
202	      return {
203	        ...c,
204	        isUnread: dom.isUnread || c.unreadCount > 0,
205	        msgFromCustomer: dom.msgFromCustomer,
206	        domLastMsg: dom.domLastMsg,
207	      };
208	    }
209	    // DOM中没有的客户（不在当前渲染列表中）
210	    return {
211	      ...c,
212	      isUnread: c.unreadCount > 0,
213	      msgFromCustomer: null, // 未知
214	      domLastMsg: '',
215	    };
216	  });
217	
218	  // 分类
219	  const classified = merged.map(c => {
220	    const cls = classify(c);
221	    return { ...c, ...cls };
222	  });
223	
224	  // 统计
225	  const stats = { P0: [], P1: [], P2: [], P3: [] };
226	  for (const p of ['P0', 'P1', 'P2', 'P3']) {
227	    stats[p] = classified.filter(c => c.priority === p);
228	  }
229	
230	  console.log('\n═══════════════════════════════════');
231	  console.log('       全量客户分类结果');
232	  console.log('═══════════════════════════════════');
233	  console.log(`  总计: ${classified.length}人`);
234	  for (const [p, arr] of Object.entries(stats)) {
235	    const emoji = { P0: '🔴', P1: '🟡', P2: '🔵', P3: '⚪' }[p];
236	    const unread = arr.filter(c => c.isUnread).length;
237	    console.log(`  ${emoji} ${p}: ${arr.length}人 (未读${unread})`);
238	  }
239	
240	  // P0详情
241	  console.log('\n── 🔴 P0 紧急客户 ──');
242	  stats.P0.sort((a, b) => b.lastContactTime - a.lastContactTime).forEach(c => {
243	    const days = Math.round((Date.now() - c.lastContactTime) / (1000 * 60 * 60 * 24));
244	    const msg = (c.latestMessageContent || c.domLastMsg || '').substring(0, 70);
245	    console.log(`  ${c.isUnread ? '📩' : '  '} ${c.name} | ${c.countryCode} | ${days}d前 | ${c.reasons.join(',')} | "${msg}"`);
246	  });
247	
248	  // P1详情（前20）
249	  console.log('\n── 🟡 P1 高优客户 (前30) ──');
250	  stats.P1.sort((a, b) => b.lastContactTime - a.lastContactTime).slice(0, 30).forEach(c => {
251	    const days = Math.round((Date.now() - c.lastContactTime) / (1000 * 60 * 60 * 24));
252	    const msg = (c.latestMessageContent || c.domLastMsg || '').substring(0, 70);
253	    console.log(`  ${c.name} | ${c.countryCode} | ${days}d前 | ${c.reasons.join(',')} | "${msg}"`);
254	  });
255	  if (stats.P1.length > 30) console.log(`  ... 共${stats.P1.length}人`);
256	
257	  // 保存
258	  const now = new Date();
259	  const dateStr = now.toISOString().replace(/[:.]/g, '-').substring(0, 19);
260	
261	  const output = {
262	    capturedAt: now.toISOString(),
263	    stats: {
264	      total: classified.length,
265	      P0: stats.P0.length,
266	      P1: stats.P1.length,
267	      P2: stats.P2.length,
268	      P3: stats.P3.length,
269	      totalUnread: classified.filter(c => c.isUnread).length,
270	    },
271	    customers: classified,
272	  };
273	
274	  const filename = `${dateStr}_全量客户分类.json`;
275	  writeFileSync(join(DATA_DIR, filename), JSON.stringify(output, null, 2));
276	  console.log(`\n✅ 已保存: ${filename}`);
277	
278	  // P0/P1深抓清单
279	  const p0p1 = [...stats.P0, ...stats.P1].map(c => ({
280	    name: c.name,
281	    countryCode: c.countryCode,
282	    priority: c.priority,
283	    tier: c.tier,
284	    reasons: c.reasons,
285	    isUnread: c.isUnread,
286	    cid: c.cid,
287	    latestMessageContent: c.latestMessageContent,
288	  }));
289	
290	  const listFilename = `${dateStr}_P0P1深抓清单.json`;
291	  writeFileSync(join(DATA_DIR, listFilename), JSON.stringify(p0p1, null, 2));
292	  console.log(`✅ P0/P1深抓清单: ${listFilename} (${p0p1.length}人)`);
293	}
294	
295	main().catch(err => {
296	  console.error('[extract-v2] 错误:', err.message);
297	  process.exit(1);
298	});
