40	// ============================================================
41	// Scroll sidebar to load ALL conversations into DOM
42	// Xiaoman uses virtual scrolling — only ~22 items rendered at a time.
43	// Without this, all other customers are invisible and unclickable.
44	// ============================================================
45	async function scrollSidebarToLoadAll(frame) {
46	  const container = await frame.evaluateHandle(() => {
47	    return document.querySelector('.seller-conversation-list') ||
48	      document.querySelector('.conversation-list-content') ||
49	      document.querySelector('.im-conversation-list-container');
50	  });
51	
52	  if (!container) return;
53	
54	  const seen = new Set();
55	  let lastCount = 0;
56	  let stableRounds = 0;
57	  let totalItems = 0;
58	
59	  for (let round = 0; round < 80; round++) {
60	    // Scroll down one viewport height
61	    const { newItems, total } = await frame.evaluate(({ seenArr }) => {
62	      const list = document.querySelector('.seller-conversation-list') ||
63	        document.querySelector('.conversation-list-content') ||
64	        document.querySelector('.im-conversation-list-container');
65	      if (!list) return { newItems: 0, total: 0 };
66	
67	      const items = document.querySelectorAll('.contact-item-container');
68	      let fresh = 0;
69	      items.forEach(el => {
70	        const text = el.textContent || '';
71	        if (!seenArr.includes(text.substring(0, 40))) {
72	          seenArr.push(text.substring(0, 40));
73	          fresh++;
74	        }
75	      });
76	
77	      list.scrollTop += list.clientHeight * 0.7;
78	      return { newItems: fresh, total: items.length };
79	    }, { seenArr: Array.from(seen) });
80	
81	    // Update seen set from frame evaluation side effect isn't possible directly,
82	    // so track via total count
83	    if (total === lastCount) {
84	      stableRounds++;
85	      if (stableRounds >= 5) break;
86	    } else {
87	      stableRounds = 0;
88	      lastCount = total;
89	      totalItems = total;
90	    }
91	
92	    await new Promise(r => setTimeout(r, 180));
93	  }
94	
95	  // Final: scroll back to top so unread items are at the top
96	  await frame.evaluate(() => {
97	    const list = document.querySelector('.seller-conversation-list') ||
98	      document.querySelector('.conversation-list-content');
99	    if (list) list.scrollTop = 0;
100	  });
101	  await new Promise(r => setTimeout(r, 300));
102	
103	  console.log(`  侧边栏加载完成: ~${totalItems} 项`);
104	}
105	
106	// ============================================================
107	// Fuzzy name matching — handles discrepancies between
108	// window variable names and DOM regex-parsed names
109	// ============================================================
110	function fuzzyMatchName(domName, targetName) {
111	  if (!domName || !targetName) return false;
112	  const d = domName.toLowerCase().trim();
113	  const t = targetName.toLowerCase().trim();
114	  if (d === t) return true;
115	  if (d.includes(t) || t.includes(d)) return true;
116	  // Check first name match (e.g., "Peggy" matches "Peggy Hamungala")
117	  const dParts = d.split(/\s+/);
118	  const tParts = t.split(/\s+/);
119	  if (dParts.length >= 1 && tParts.length >= 1) {
120	    if (dParts[0] === tParts[0]) return true;
121	    if (dParts.length >= 2 && tParts.length >= 2 && dParts[0] === tParts[0] && dParts[1] === tParts[1]) return true;
122	  }
123	  return false;
124	}
125	
126	async function clickConversation(frame, index) {
127	  await frame.evaluate((idx) => {
128	    const containers = document.querySelectorAll('.contact-item-container');
129	    const target = containers[idx];
130	    if (target) {
131	      target.scrollIntoView({ block: 'center' });
132	      target.click();
133	    }
134	  }, index);
135	  // Dynamic wait: poll until conversation header updates
136	  // No more fixed 1500ms timeout — the root cause of DOM串位
137	  for (let i = 0; i < 20; i++) {
138	    await new Promise(r => setTimeout(r, 300));
139	    const loaded = await frame.evaluate(() => {
140	      const header = document.querySelector('.im-header-title, .session-header-title, .chat-header-title');
141	      return header ? (header.textContent || '').trim() : '';
142	    });
143	    if (loaded.length > 0) break;
144	  }
145	}
146	
147	// ============================================================
148	// Identity verification — prevent DOM串位
149	// After clicking a customer, verify the loaded conversation
150	// actually belongs to them before reading messages.
151	// ============================================================
152	async function verifyConversationIdentity(frame, expectedName) {
153	  for (let attempt = 0; attempt < 10; attempt++) {
154	    const actualName = await frame.evaluate(() => {
155	      const header = document.querySelector('.im-header-title, .session-header-title, .chat-header-title');
156	      if (header) return (header.textContent || '').trim();
157	      // Fallback: check sidebar selection
158	      const selected = document.querySelector('.contact-item-container.selected .contact-right');
159	      if (selected) return (selected.textContent || '').trim().substring(0, 30);
160	      return '';
161	    });
162	
163	    // Fuzzy match: the header may contain extra info (company, country)
164	    if (actualName && (
165	      actualName.includes(expectedName) ||
166	      expectedName.includes(actualName) ||
167	      actualName.toLowerCase() === expectedName.toLowerCase()
168	    )) {
169	      return true;
170	    }
171	
172	    // If no name detected yet, wait and retry
173	    if (!actualName || actualName.length === 0) {
174	      await new Promise(r => setTimeout(r, 500));
175	      continue;
176	    }
177	
178	    // Name mismatch! Previous conversation still showing.
179	    // Wait longer for iframe to actually switch.
180	    console.log(` [⏳等待切换: 期望${expectedName}, 实际${actualName}]`);
181	    await new Promise(r => setTimeout(r, 800));
182	  }
183	
184	  return false;
185	}
186	
187	async function waitForMessages(frame, targetName) {
188	  for (let i = 0; i < 15; i++) {
189	    const hasContent = await frame.evaluate(() =>
190	      document.querySelectorAll('.session-rich-content.text, .session-rich-content.card').length > 0
191	    );
192	    if (hasContent) {
193	      // Verify identity before returning
194	      if (targetName) {
195	        const verified = await verifyConversationIdentity(frame, targetName);
196	        if (verified) return true;
197	        // Not verified — keep waiting
198	        await new Promise(r => setTimeout(r, 500));
199	        continue;
200	      }
201	      return true;
202	    }
203	    await new Promise(r => setTimeout(r, 500));
204	  }
205	  return false;
206	}
207	
208	async function scrollChatToLoadAll(frame, { maxScrolls = 40, stableThreshold = 3 } = {}) {
209	  const containerInfo = await frame.evaluate(() => {
210	    const selectors = [
211	      '.message-list-container', '.chat-list', '.im-chat-list',
212	      '.message-list', '[class*="message-list"]', '[class*="chat-list"]',
213	      '[class*="chat-content"]', '.session-message-list-wrapper',
214	    ];
215	    for (const sel of selectors) {
216	      const el = document.querySelector(sel);
217	      if (el && el.scrollHeight > el.clientHeight) {
218	        return { selector: sel, scrollHeight: el.scrollHeight, clientHeight: el.clientHeight };
219	      }
220	    }
221	    return null;
222	  });
223	
224	  if (!containerInfo) return 0;
225	
226	  let prevCount = 0;
227	  let stableCount = 0;
228	  let totalScrolled = 0;
229	
230	  for (let i = 0; i < maxScrolls; i++) {
231	    const { count, scrolled } = await frame.evaluate((sel) => {
232	      const container = document.querySelector(sel);
233	      if (!container) return { count: 0, scrolled: false };
234	      const old = container.scrollTop;
235	      container.scrollTop = 0;
236	      return {
237	        count: document.querySelectorAll('.message-item-wrapper.messenger').length,
238	        scrolled: old > 0,
239	      };
240	    }, containerInfo.selector);
241	
242	    totalScrolled++;
243	    if (scrolled) await new Promise(r => setTimeout(r, 600));
244	
245	    const newCount = await frame.evaluate(() =>
246	      document.querySelectorAll('.message-item-wrapper.messenger').length
247	    );
248	
249	    if (newCount === prevCount) {
250	      stableCount++;
251	      if (stableCount >= stableThreshold) break;
252	    } else {
253	      stableCount = 0;
254	    }
255	    prevCount = newCount;
256	    if (!scrolled) break;
257	  }
258	
259	  return prevCount;
260	}
261	
262	async function getRenderedMessages(frame) {
263	  return frame.evaluate(() => {
264	    const messages = [];
265	    document.querySelectorAll('.message-item-wrapper.messenger').forEach(wrapper => {
266	      const isLeft = wrapper.classList.contains('item-left');
267	      const isRight = wrapper.classList.contains('item-right');
268	      const securityEl = wrapper.querySelector('.session-security');
269	      if (securityEl) return;
270	
271	      const textEl = wrapper.querySelector('.session-rich-content.text');
272	      const cardEl = wrapper.querySelector('.session-rich-content.card');
273	
274	      let content = '';
275	      let isCard = false;
276	      let cardData = null;
277	
278	      if (textEl) {
279	        content = textEl.textContent.trim()
280	          .replace(/翻译中…反馈$/, '')
281	          .replace(/由阿里翻译提供反馈$/, '')
282	          .replace(/阿里国际Marco大模型翻译反馈$/, '')
283	          .replace(/由阿里翻译提供$/, '')
284	          .trim();
285	      } else if (cardEl) {
286	        content = cardEl.textContent.trim();
287	        isCard = true;
288	        const expinfo = cardEl.getAttribute('data-expinfo');
289	        if (expinfo) {
290	          try { cardData = JSON.parse(expinfo); } catch (e) {}
291	        }
292	      } else {
293	        return;
294	      }
295	
296	      const timeEl = wrapper.querySelector('p.item-base-info span:last-child');
297	      const timestamp = timeEl ? (timeEl.textContent || '').trim() : null;
298	
299	      const contentImgs = wrapper.querySelectorAll('img');
300	      const hasImages = Array.from(contentImgs).some(img => {
301	        if (img.classList.contains('emotion')) return false;
302	        const s = img.src || '';
303	        if (!s.startsWith('http')) return false;
304	        if (s.includes('atmgateway-client.alibaba.com/smily')) return false;
305	        if (s.includes('clouddisk.alibaba.com')) return false;
306	        return true;
307	      });
308	
309	      messages.push({
310	        side: isLeft ? 'received' : isRight ? 'sent' : 'system',
311	        content: content.substring(0, 2000),
312	        timestamp,
313	        isCard,
314	        cardData,
315	        hasImages,
316	      });
317	    });
318	
319	    return messages;
320	  });
321	}
322	
323	async function findCustomerIndex(frame, targetName) {
324	  const list = await getConversationList(frame);
325	  const match = list.find(c => c.name === targetName);
326	  return match ? match.index : -1;
327	}
328	
329	async function main() {
330	  // 读取P0/P1清单
331	  const files = (await import('fs')).readdirSync(DATA_DIR).filter(f => f.includes('P0P1深抓清单'));
332	  if (files.length === 0) {
333	    console.log('❌ 未找到P0P1深抓清单，先运行 extract-all-v2.mjs');
334	    return;
335	  }
336	  const listFile = files.sort().reverse()[0];
337	  const p0p1List = JSON.parse(readFileSync(join(DATA_DIR, listFile), 'utf8'));
338	
339	  console.log(`[deep-scrape] 准备深抓 ${p0p1List.length} 个P0/P1客户`);
340	  console.log(`  P0: ${p0p1List.filter(c => c.priority === 'P0').length}人`);
341	  console.log(`  P1: ${p0p1List.filter(c => c.priority === 'P1').length}人\n`);
342	
343	  const { browser, talkFrame } = await connect();
344	  console.log('✅ 已连接\n');
345	
346	  const results = [];
347	  const skipped = [];
348	  let successCount = 0;
349	
350	  try {
351	    // ⭐ Scroll sidebar to load ALL conversations into DOM (fixes 15%→90%+)
352	    console.log('滚动侧边栏加载全部会话...');
353	    await scrollSidebarToLoadAll(talkFrame);
354	
355	    // 获取完整会话列表（现在DOM里有全部人了）
356	    const convList = await getConversationList(talkFrame);
357	    console.log(`当前DOM会话列表: ${convList.length}个\n`);
358	
359	    // 创建名字→索引映射（使用模糊匹配）
360	    const nameToIndex = {};
361	    convList.forEach(c => { nameToIndex[c.name] = c.index; });
362	
363	    // 辅助函数：用模糊匹配找到客户的DOM索引
364	    function findInConvList(targetName) {
365	      // 精确匹配
366	      if (nameToIndex[targetName] !== undefined) return nameToIndex[targetName];
367	      // 模糊匹配
368	      for (const c of convList) {
369	        if (fuzzyMatchName(c.name, targetName)) return c.index;
370	      }
371	      return undefined;
372	    }
373	
374	    // 只处理P0客户（优先级最高）
375	    const p0Customers = p0p1List.filter(c => c.priority === 'P0');
376	    const p1Customers = p0p1List.filter(c => c.priority === 'P1');
377	
378	    const toScrape = [...p0Customers, ...p1Customers];
379	
380	    for (let i = 0; i < toScrape.length; i++) {
381	      const target = toScrape[i];
382	      const idx = findInConvList(target.name);
383	
384	      if (idx === undefined) {
385	        skipped.push(target.name + '(DOM中未找到)');
386	        continue;
387	      }
388	
389	      process.stdout.write(`[${i + 1}/${toScrape.length}] ${target.priority} ${target.name}...`);
390	
391	      try {
392	        await clickConversation(talkFrame, idx);
393	        const hasMsgs = await waitForMessages(talkFrame, target.name);
394	
395	        if (!hasMsgs) {
396	          console.log(' ⚠️ 无消息或身份验证失败');
397	          continue;
398	        }
399	
400	        // Identity confirmed — now safe to scroll and read
401	        const msgCount = await scrollChatToLoadAll(talkFrame);
402	        const messages = await getRenderedMessages(talkFrame);
403	
404	        results.push({
405	          name: target.name,
406	          priority: target.priority,
407	          tier: target.tier,
408	          countryCode: target.countryCode,
409	          reasons: target.reasons,
410	          messageCount: messages.length,
411	          messages,
412	          scrapedAt: new Date().toISOString(),
413	        });
414	
415	        successCount++;
416	        console.log(` ✅ ${messages.length}条`);
417	      } catch (e) {
418	        console.log(` ❌ ${e.message.substring(0, 50)}`);
419	      }
420	
421	      // Refresh index every 5 to avoid stale positions
422	      if ((i + 1) % 5 === 0) {
423	        const refreshed = await getConversationList(talkFrame);
424	        refreshed.forEach(c => { nameToIndex[c.name] = c.index; });
425	      }
426	    }
427	
428	    // 保存
429	    const now = new Date();
430	    const dateStr = now.toISOString().replace(/[:.]/g, '-').substring(0, 19);
431	    const outputPath = join(DATA_DIR, `deep_scrape_${dateStr}.json`);
432	
433	    writeFileSync(outputPath, JSON.stringify({
434	      scrapedAt: now.toISOString(),
435	      totalTargeted: toScrape.length,
436	      successCount,
437	      skippedCount: skipped.length,
438	      skipped,
439	      results,
440	    }, null, 2));
441	
442	    console.log(`\n✅ 深抓完成: ${successCount}/${toScrape.length} 成功, ${skipped.length} 跳过`);
443	    console.log(`   已保存: ${outputPath}`);
444	  } finally {
445	    // Don't close browser - it's shared
446	  }
447	}
448	
449	main().catch(err => {
450	  console.error('[deep-scrape] 错误:', err.message);
451	  process.exit(1);
452	});
