585	  if (/sample|样品/.test(msg)) return '安排寄样 + 品质背书';
586	  if (/price|cost|报价|how much/.test(msg)) return '补发报价 + 差异化话术';
587	  if (/ship|delivery|海运|快递/.test(msg)) return '确认物流方式 + 时效说明';
588	  if (/payment|pay|deposit/.test(msg)) return '催款 + 发货时间表';
589	  if (/complaint|return|refund/i.test(msg)) return '优先处理售后';
590	  return '温和跟进 + 品质钩子';
591	}
592	
593	function getCountryName(code) {
594	  const map = {
595	    US: '美国', UK: '英国', DE: '德国', FR: '法国', IT: '意大利', ES: '西班牙',
596	    SA: '沙特', AE: '阿联酋', OM: '阿曼', QA: '卡塔尔', KW: '科威特', BH: '巴林',
597	    IQ: '伊拉克', LY: '利比亚', EG: '埃及', SY: '叙利亚', JO: '约旦', LB: '黎巴嫩',
598	    NG: '尼日利亚', ZA: '南非', ZM: '赞比亚', ZW: '津巴布韦', CD: '刚果(金)',
599	    CG: '刚果(布)', CM: '喀麦隆', CI: '科特迪瓦', SN: '塞内加尔', ML: '马里',
600	    GH: '加纳', KE: '肯尼亚', TZ: '坦桑尼亚', UG: '乌干达', MZ: '莫桑比克',
601	    IN: '印度', PK: '巴基斯坦', ID: '印尼', PH: '菲律宾', MY: '马来西亚',
602	    AU: '澳大利亚', CA: '加拿大', RU: '俄罗斯', BY: '白俄罗斯', UZ: '乌兹别克斯坦',
603	    GE: '格鲁吉亚', MU: '毛里求斯', GA: '加蓬', TG: '多哥', CL: '智利', MX: '墨西哥',
604	    NO: '挪威',
605	  };
606	  return map[code] || code || '未知';
607	}
608	
609	function detectLanguage(msg) {
610	  if (/[؀-ۿ]/.test(msg)) return '阿拉伯语';
611	  if (/[àâçéèêëîïôûùüÿœæ]/i.test(msg)) return '法语';
612	  if (/[áéíóúñ¿¡]/i.test(msg)) return '西班牙语';
613	  if (/[А-Яа-я]/.test(msg)) return '俄语';
614	  if (/[^\x00-\x7F]/.test(msg)) return '其他语言';
615	  return '英语';
616	}
617	
618	// ============ 主入口 ============
619	async function main() {
620	  // 找最新分类文件
621	  const files = readdirSync(DATA_DIR).filter(f => f.includes('全量客户分类'));
622	  if (files.length === 0) {
623	    console.log('❌ 未找到分类数据，先运行 extract-all-v2.mjs');
624	    return;
625	  }
626	  const classifyFile = files.sort().reverse()[0];
627	  const classifyData = JSON.parse(readFileSync(join(DATA_DIR, classifyFile), 'utf8'));
628	
629	  // 找最新深抓文件
630	  const deepFiles = readdirSync(DATA_DIR).filter(f => f.startsWith('deep_scrape_'));
631	  let deepData = null;
632	  if (deepFiles.length > 0) {
633	    const deepFile = deepFiles.sort().reverse()[0];
634	    deepData = JSON.parse(readFileSync(join(DATA_DIR, deepFile), 'utf8'));
635	  }
636	
637	  console.log(`分类数据: ${classifyFile} (${classifyData.customers?.length || 0}人)`);
638	  if (deepData) console.log(`深抓数据: ${deepFiles.sort().reverse()[0]} (${deepData.results?.length || 0}人)`);
639	
640	  const { doc, dateStr } = await generateBattleReport(classifyData, deepData);
641	
642	  const buffer = await Packer.toBuffer(doc);
643	  const outputPath = join(REPORTS_DIR, `外贸跟进战报_${dateStr}.docx`);
644	  writeFileSync(outputPath, buffer);
645	
646	  console.log(`\n✅ 战报已生成: ${outputPath}`);
647	}
648	
649	main().catch(err => {
650	  console.error('生成失败:', err.message);
651	  process.exit(1);
652	});
