/**
 * AI外贸顾问 — Word战报生成器
 * 生成格式美观的 .docx 日报：概览 → P0五步分析 → P1摘要 → P2/P3策略
 *
 * 用法: node generate-battle-report.mjs [分类JSON路径] [深抓JSON路径]
 * 默认读取 data/ 目录下最新文件
 */

import {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  HeadingLevel, AlignmentType, WidthType, BorderStyle,
  ShadingType, TableLayoutType, PageBreak, Header, Footer, PageNumber,
} from 'docx';
import { writeFileSync, readFileSync, readdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..', 'data');
const REPORTS_DIR = join(__dirname, '..', 'reports');

// ============ 颜色系统 ============
const C = {
  dark: '1A1A2E',
  primary: '16213E',
  accent: 'E94560',
  gold: 'F5A623',
  green: '00B894',
  blue: '0984E3',
  purple: '6C5CE7',
  gray: '636E72',
  lightGray: 'B2BEC3',
  bg: 'F8F9FA',
  white: 'FFFFFF',
  red: 'D63031',
  orange: 'E17055',
};

// ============ 工具函数 ============
function cell(text, opts = {}) {
  const {
    bold = false, color = C.dark, size = 18, align = AlignmentType.LEFT,
    bg = undefined, width = undefined, colSpan = 1,
  } = opts;

  return new TableCell({
    children: [new Paragraph({
      children: [new TextRun({ text: String(text), bold, color, size, font: '微软雅黑' })],
      alignment: align,
    })],
    width: width ? { size: width, type: WidthType.DXA } : undefined,
    shading: bg ? { fill: bg, type: ShadingType.CLEAR } : undefined,
    columnSpan: colSpan,
    verticalAlign: 'center',
  });
}

function heading(text, level = 1) {
  const sizes = { 1: 32, 2: 26, 3: 22 };
  const colors = { 1: C.primary, 2: C.dark, 3: C.primary };
  return new Paragraph({
    children: [new TextRun({ text, bold: true, size: sizes[level] || 22, color: colors[level] || C.dark, font: '微软雅黑' })],
    spacing: { before: level === 1 ? 400 : 200, after: 150 },
    border: level === 1 ? { bottom: { style: BorderStyle.SINGLE, size: 2, color: C.accent } } : undefined,
  });
}

function spacer(h = 100) {
  return new Paragraph({ spacing: { before: h, after: 0 }, children: [] });
}

function divider() {
  return new Paragraph({
    children: [new TextRun({ text: '─'.repeat(60), size: 14, color: C.lightGray })],
    spacing: { before: 100, after: 100 },
  });
}

function p0Badge() {
  return new TextRun({ text: ' P0 ', bold: true, size: 16, color: C.white, font: '微软雅黑', highlight: C.red });
}

function p1Badge() {
  return new TextRun({ text: ' P1 ', bold: true, size: 16, color: C.white, font: '微软雅黑', highlight: C.orange });
}

function tag(text, color = C.blue) {
  return new TextRun({ text: ` ${text} `, size: 16, color: C.white, font: '微软雅黑', highlight: color });
}

// ============ 主报告生成 ============
export async function generateBattleReport(classifyData, deepData) {
  const now = new Date();
  const dateStr = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}-${String(now.getDate()).padStart(2,'0')}`;

  const stats = classifyData.stats || {};
  const customers = classifyData.customers || [];

  const p0Customers = customers.filter(c => c.priority === 'P0');
  const p1Customers = customers.filter(c => c.priority === 'P1');
  const p2Customers = customers.filter(c => c.priority === 'P2');
  const p3Customers = customers.filter(c => c.priority === 'P3');

  // 合并深抓数据
  const deepMap = {};
  if (deepData?.results) {
    deepData.results.forEach(r => { deepMap[r.name] = r; });
  }

  const children = [];

  // ==================== 封面 ====================
  children.push(
    spacer(600),
    new Paragraph({
      children: [new TextRun({ text: '外贸跟进战报', size: 52, bold: true, color: C.primary, font: '微软雅黑' })],
      alignment: AlignmentType.CENTER,
    }),
    new Paragraph({
      children: [new TextRun({ text: 'DAILY BATTLE REPORT', size: 24, color: C.gray, font: '微软雅黑' })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 200 },
    }),
    divider(),
    new Paragraph({
      children: [new TextRun({ text: `益阳市小星星服饰有限公司  |  ${dateStr}  |  小满TM全量快照`, size: 20, color: C.gray, font: '微软雅黑' })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 100 },
    }),
    new Paragraph({
      children: [new TextRun({ text: `总计客户: ${stats.total || customers.length}  |  P0紧急: ${stats.P0 || p0Customers.length}  |  P1高优: ${stats.P1 || p1Customers.length}`, size: 20, color: C.dark, font: '微软雅黑' })],
      alignment: AlignmentType.CENTER,
    }),
    new Paragraph({ children: [new PageBreak()] }),
  );

  // ==================== 一、总览面板 ====================
  children.push(heading('一、总览面板', 1));

  // 统计卡片表
  const overviewRows = [
    new TableRow({
      children: [
        cell('🔴 P0 紧急', { bold: true, color: C.white, size: 22, align: AlignmentType.CENTER, bg: C.red, width: 2200 }),
        cell('🟡 P1 高优', { bold: true, color: C.white, size: 22, align: AlignmentType.CENTER, bg: C.orange, width: 2200 }),
        cell('🔵 P2 中优', { bold: true, color: C.white, size: 22, align: AlignmentType.CENTER, bg: C.blue, width: 2200 }),
        cell('⚪ P3 休眠', { bold: true, color: C.white, size: 22, align: AlignmentType.CENTER, bg: C.gray, width: 2200 }),
      ],
    }),
    new TableRow({
      children: [
        cell(`${p0Customers.length} 人`, { bold: true, size: 36, align: AlignmentType.CENTER }),
        cell(`${p1Customers.length} 人`, { bold: true, size: 36, align: AlignmentType.CENTER }),
        cell(`${p2Customers.length} 人`, { bold: true, size: 36, align: AlignmentType.CENTER }),
        cell(`${p3Customers.length} 人`, { bold: true, size: 36, align: AlignmentType.CENTER }),
      ],
    }),
  ];

  children.push(
    new Table({ rows: overviewRows, width: { size: 100, type: WidthType.PERCENTAGE }, layout: TableLayoutType.FIXED }),
    spacer(300),
  );

  // P0客户快速索引表
  children.push(heading('P0 紧急客户快速索引', 3));
  const p0IndexRows = [
    new TableRow({
      tableHeader: true,
      children: [
        cell('#', { bold: true, color: C.white, bg: C.primary, width: 500, align: AlignmentType.CENTER }),
        cell('客户名', { bold: true, color: C.white, bg: C.primary, width: 2200 }),
        cell('国家', { bold: true, color: C.white, bg: C.primary, width: 900 }),
        cell('天数', { bold: true, color: C.white, bg: C.primary, width: 700, align: AlignmentType.CENTER }),
        cell('卡点', { bold: true, color: C.white, bg: C.primary, width: 1500 }),
        cell('最新消息', { bold: true, color: C.white, bg: C.primary, width: 3800 }),
      ],
    }),
  ];

  p0Customers.sort((a, b) => b.lastContactTime - a.lastContactTime).forEach((c, i) => {
    const daysAgo = Math.round((Date.now() - (c.lastContactTime || c.modifyTime || 0)) / 86400000);
    const unreadIcon = c.isUnread ? '📩 ' : '';
    const msg = (c.latestMessageContent || c.domLastMsg || '').substring(0, 80);
    const blockReason = c.reasons?.join('/') || '';

    p0IndexRows.push(new TableRow({
      children: [
        cell(String(i+1), { align: AlignmentType.CENTER, bold: true, color: C.red, size: 18 }),
        cell(unreadIcon + c.name, { bold: true }),
        cell(c.countryCode || '?', { align: AlignmentType.CENTER }),
        cell(`${daysAgo}d`, { align: AlignmentType.CENTER, color: daysAgo <= 1 ? C.red : daysAgo <= 3 ? C.orange : C.gray, bold: true }),
        cell(blockReason, { size: 16, color: C.gray }),
        cell(msg, { size: 16 }),
      ],
    }));
  });

  children.push(
    new Table({ rows: p0IndexRows, width: { size: 100, type: WidthType.PERCENTAGE }, layout: TableLayoutType.FIXED }),
    new Paragraph({ children: [new PageBreak()] }),
  );

  // ==================== 二、P0 五步深度分析 ====================
  children.push(heading('二、P0 紧急客户 — 五步深度分析', 1));

  // 预置的五步分析数据（由CC生成）
  const analyses = getP0Analyses(p0Customers, deepMap);

  for (const analysis of analyses) {
    const isUnread = analysis.isUnread;
    children.push(
      new Paragraph({
        children: [
          new TextRun({ text: `${analysis.name}  `, size: 28, bold: true, color: C.dark, font: '微软雅黑' }),
          new TextRun({ text: analysis.country, size: 20, color: C.gray, font: '微软雅黑' }),
          isUnread ? new TextRun({ text: '  📩 未读', size: 18, color: C.red, font: '微软雅黑' }) : new TextRun({ text: '' }),
        ],
        spacing: { before: 400, after: 100 },
        border: { bottom: { style: BorderStyle.SINGLE, size: 1, color: C.accent } },
      }),
    );

    // 第一步：客户画像
    children.push(
      new Paragraph({
        children: [new TextRun({ text: '第一步：客户画像', bold: true, size: 20, color: C.primary, font: '微软雅黑' })],
        spacing: { before: 150, after: 60 },
      }),
    );
    for (const line of analysis.step1) {
      children.push(new Paragraph({
        children: [new TextRun({ text: `  • ${line}`, size: 18, color: C.dark, font: '微软雅黑' })],
        spacing: { after: 30 },
      }));
    }

    // 第二步：卡点诊断
    children.push(
      new Paragraph({
        children: [new TextRun({ text: '第二步：卡点诊断', bold: true, size: 20, color: C.red, font: '微软雅黑' })],
        spacing: { before: 100, after: 60 },
      }),
    );
    for (const line of analysis.step2) {
      children.push(new Paragraph({
        children: [new TextRun({ text: `  • ${line}`, size: 18, color: C.dark, font: '微软雅黑' })],
        spacing: { after: 30 },
      }));
    }

    // 第三步：策略推演
    children.push(
      new Paragraph({
        children: [new TextRun({ text: '第三步：策略推演', bold: true, size: 20, color: C.orange, font: '微软雅黑' })],
        spacing: { before: 100, after: 60 },
      }),
    );

    // 策略对比表
    const strategyRows = [
      new TableRow({
        tableHeader: true,
        children: [
          cell('', { bold: true, color: C.white, bg: C.primary, width: 1200 }),
          cell('方案A（常规）', { bold: true, color: C.white, bg: C.gray, width: 3400 }),
          cell('方案B（推荐）', { bold: true, color: C.white, bg: C.green, width: 3400 }),
        ],
      }),
    ];
    for (const row of analysis.step3) {
      strategyRows.push(new TableRow({
        children: [
          cell(row.label, { bold: true }),
          cell(row.planA, { size: 17 }),
          cell(row.planB, { size: 17 }),
        ],
      }));
    }
    children.push(
      new Table({ rows: strategyRows, width: { size: 100, type: WidthType.PERCENTAGE }, layout: TableLayoutType.FIXED }),
    );

    // 第四步：具体话术
    children.push(
      new Paragraph({
        children: [new TextRun({ text: '第四步：具体话术', bold: true, size: 20, color: C.green, font: '微软雅黑' })],
        spacing: { before: 100, after: 60 },
      }),
    );
    children.push(new Paragraph({
      children: [new TextRun({ text: `  💬 ${analysis.step4 || '见下方话术框'}`, size: 18, color: C.dark, font: '微软雅黑' })],
      spacing: { after: 30 },
    }));
    for (const line of (analysis.step4Lines || [])) {
      children.push(new Paragraph({
        children: [new TextRun({ text: `    ${line}`, size: 17, color: C.dark, font: '微软雅黑' })],
        spacing: { after: 20 },
      }));
    }

    // 第五步：分支预演
    children.push(
      new Paragraph({
        children: [new TextRun({ text: '第五步：分支预演', bold: true, size: 20, color: C.purple, font: '微软雅黑' })],
        spacing: { before: 100, after: 60 },
      }),
    );
    for (const line of analysis.step5) {
      children.push(new Paragraph({
        children: [new TextRun({ text: `  ${line}`, size: 17, color: C.dark, font: '微软雅黑' })],
        spacing: { after: 25 },
      }));
    }

    children.push(divider());
  }

  // ==================== 三、P1 摘要表 ====================
  children.push(new Paragraph({ children: [new PageBreak()] }));
  children.push(heading('三、P1 高优客户摘要', 1));

  const p1TableRows = [
    new TableRow({
      tableHeader: true,
      children: [
        cell('客户', { bold: true, color: C.white, bg: C.orange, width: 2000 }),
        cell('国家', { bold: true, color: C.white, bg: C.orange, width: 800, align: AlignmentType.CENTER }),
        cell('天数', { bold: true, color: C.white, bg: C.orange, width: 600, align: AlignmentType.CENTER }),
        cell('状态', { bold: true, color: C.white, bg: C.orange, width: 1200 }),
        cell('推荐动作', { bold: true, color: C.white, bg: C.orange, width: 3400 }),
      ],
    }),
  ];

  p1Customers.sort((a, b) => b.lastContactTime - a.lastContactTime).slice(0, 33).forEach(c => {
    const daysAgo = Math.round((Date.now() - (c.lastContactTime || c.modifyTime || 0)) / 86400000);
    p1TableRows.push(new TableRow({
      children: [
        cell(c.name, { size: 17 }),
        cell(c.countryCode || '?', { align: AlignmentType.CENTER, size: 17 }),
        cell(`${daysAgo}d`, { align: AlignmentType.CENTER, size: 17, color: daysAgo <= 7 ? C.orange : C.gray }),
        cell(c.reasons?.join('/') || '', { size: 16, color: C.gray }),
        cell(getP1Action(c), { size: 16 }),
      ],
    }));
  });

  children.push(
    new Table({ rows: p1TableRows, width: { size: 100, type: WidthType.PERCENTAGE }, layout: TableLayoutType.FIXED }),
  );

  // ==================== 四、P3激活策略 ====================
  children.push(spacer(300));
  children.push(heading('四、P3 休眠客户批量激活', 1));
  children.push(new Paragraph({
    children: [new TextRun({ text: `共 ${p3Customers.length} 人超过30天未联系。按区域分群激活策略如下：`, size: 20, color: C.dark, font: '微软雅黑' })],
    spacing: { after: 150 },
  }));

  // 区域统计
  const regionMap = {
    '中东': ['SA','AE','OM','QA','KW','BH','IQ','LY','EG','SY','JO','LB','YE'],
    '非洲': ['NG','ZA','ZM','ZW','CD','CG','CM','CI','SN','ML','GH','KE','TZ','UG','MZ'],
    '欧美': ['US','UK','DE','FR','IT','ES','NL','BE','CA','AU','NO','SE'],
    '其他': [],
  };
  const regionStats = { '中东': 0, '非洲': 0, '欧美': 0, '其他': 0 };
  p3Customers.forEach(c => {
    let found = false;
    for (const [region, codes] of Object.entries(regionMap)) {
      if (region === '其他') continue;
      if (codes.includes(c.countryCode || '')) { regionStats[region]++; found = true; break; }
    }
    if (!found) regionStats['其他']++;
  });

  const activateRows = [
    new TableRow({
      tableHeader: true,
      children: [
        cell('区域', { bold: true, color: C.white, bg: C.purple, width: 1500 }),
        cell('人数', { bold: true, color: C.white, bg: C.purple, width: 800, align: AlignmentType.CENTER }),
        cell('激活策略', { bold: true, color: C.white, bg: C.purple, width: 3000 }),
        cell('推荐钩子', { bold: true, color: C.white, bg: C.purple, width: 2700 }),
      ],
    }),
  ];

  const regionStrategies = {
    '中东': { strategy: '帮宝适奥运背书 + 海湾客户案例 + 新品推荐', hook: '帮宝适奥运联名实拍图 / 面料对比' },
    '非洲': { strategy: '小批量试单方案(12-20件) + 运费试算 + 推荐畅销款', hook: '小批量试单方案 / 其他非洲客户装箱视频' },
    '欧美': { strategy: 'ISO9001证书 + 产线实拍 + 免费样布 + 小批量方案', hook: 'ISO9001证书 / 产线实拍 / 免费样布' },
    '其他': { strategy: '通用新品推荐 + 工厂实力展示 + 二选一钩子', hook: '新品实拍图 / 面料对比' },
  };

  for (const [region, count] of Object.entries(regionStats)) {
    const s = regionStrategies[region];
    activateRows.push(new TableRow({
      children: [
        cell(region, { bold: true, size: 18 }),
        cell(String(count), { align: AlignmentType.CENTER, bold: true, size: 22, color: C.purple }),
        cell(s.strategy, { size: 17 }),
        cell(s.hook, { size: 16, color: C.gray }),
      ],
    }));
  }

  children.push(
    new Table({ rows: activateRows, width: { size: 100, type: WidthType.PERCENTAGE }, layout: TableLayoutType.FIXED }),
    spacer(200),
  );

  // 批量激活话术模板
  children.push(heading('批量激活话术模板', 3));
  const templateText = `Hi {Name}，好久不见！我们是小星星服饰——去年帮宝适奥运联名款吸汗巾的生产工厂。
