      ];
      analysis.step4 = `谢谢你愿意沟通。品质问题我们非常重视——请具体描述一下问题（最好有照片），我直接呈报给生产主管和老板。如果是我们的问题，全额退款或重做。这不会影响我们未来的合作。`;
      analysis.step4Lines = [
        `关键: 先认错，不推卸，给具体行动方案`,
